      "content": {{ JSON.stringify(
        'Name: ' + $json.name + '\nEmail: ' + $json.email + '\nCompany: ' + $json.company + '\nRole: ' + $json.role + '\nMessage: ' + $json.message
      ) }}
    }
  ]
}

parameters.jsCode:
// Parse the AI response and merge with the original lead fields
const lead = $('Set Lead Fields').item.json;
const aiRaw = $json.choices?.[0]?.message?.content || '{}';

let parsed = { score: 0, intent: 'unrelated', rationale: 'Failed to parse AI response' };
try {
  parsed = JSON.parse(aiRaw);
  parsed.score = Math.max(1, Math.min(10, parseInt(parsed.score, 10) || 0));
} catch (e) {
  parsed.rationale = 'AI returned malformed JSON: ' + aiRaw.slice(0, 200);
}

return [{
  json: {
    ...lead,
    score: parsed.score,
    intent: parsed.intent,
    rationale: parsed.rationale
  }
}];
